import React, { useMemo, useState, useEffect, useRef } from 'react';
import {
  Box,
  Typography,
  Stack,
  CircularProgress,
} from '@mui/material';
import {
  TrendingUp as TrendingUpIcon,
  TrendingDown as TrendingDownIcon,
} from '@mui/icons-material';
import PerformanceCharts from '../components/PerformanceCharts';
import CalendarLockedOverlay from '../components/calendars/CalendarLockedOverlay';
import OrionFab from '../components/orion/OrionFab';
import { useOrion } from '../contexts/OrionContext';
import { Calendar } from '../types/calendar';

const APP_HEADER_HEIGHT = 64;
const SWITCH_SPINNER_MS = 350;

interface PerformancePageProps {
  /** Plumbed from App.tsx so calendar-property edits made from this page persist. */
  onUpdateCalendar?: (id: string, updates: Partial<Calendar>) => Promise<void> | void;
  /** Triggers the Create Calendar dialog when the lock overlay's CTA is clicked. */
  onCreateCalendar?: () => void;
}

/**
 * Performance analytics tied to the globally-selected calendar (from
 * AppHeader). Switching calendars from the header triggers a brief spinner
 * overlay so the PerformanceCharts remount feels intentional rather than
 * abrupt.
 */
const PerformancePage: React.FC<PerformancePageProps> = ({
  onUpdateCalendar,
  onCreateCalendar,
}) => {
  const { selectedCalendar, availableCalendars, setSelectedCalendarId } =
    useOrion();

  // Default to the first available calendar when none is selected yet.
  useEffect(() => {
    if (selectedCalendar) return;
    if (availableCalendars.length === 0) return;
    setSelectedCalendarId(availableCalendars[0].id);
  }, [selectedCalendar, availableCalendars, setSelectedCalendarId]);

  // Brief overlay spinner when the calendar swaps so the chart remount reads
  // as a deliberate transition rather than a flash.
  const [isSwitching, setIsSwitching] = useState(false);
  const switchTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const prevCalIdRef = useRef<string | undefined>(selectedCalendar?.id);
  useEffect(() => {
    if (prevCalIdRef.current === selectedCalendar?.id) return;
    prevCalIdRef.current = selectedCalendar?.id;
    setIsSwitching(true);
    if (switchTimerRef.current) clearTimeout(switchTimerRef.current);
    switchTimerRef.current = setTimeout(
      () => setIsSwitching(false),
      SWITCH_SPINNER_MS,
    );
  }, [selectedCalendar?.id]);

  useEffect(() => {
    return () => {
      if (switchTimerRef.current) clearTimeout(switchTimerRef.current);
    };
  }, []);

  // Wrap App's onUpdateCalendar into the (calendarId, updateCallback) signature
  // PerformanceCharts expects.
  const onUpdateCalendarProperty = useMemo(() => {
    if (!onUpdateCalendar || !selectedCalendar) return undefined;
    return async (
      calendarId: string,
      updateCallback: (calendar: Calendar) => Calendar
    ): Promise<Calendar | undefined> => {
      const target = availableCalendars.find((c) => c.id === calendarId);
      if (!target) return undefined;
      const updated = updateCallback(target);
      await onUpdateCalendar(calendarId, updated);
      return updated;
    };
  }, [onUpdateCalendar, selectedCalendar, availableCalendars]);

  // ---- Render ----

  if (availableCalendars.length === 0) {
    return (
      <Box
        sx={{
          position: 'relative',
          minHeight: `calc(100vh - ${APP_HEADER_HEIGHT}px)`,
        }}
      >
        <CalendarLockedOverlay
          onCreateCalendar={onCreateCalendar}
          subtitle="Create a calendar to start tracking trades and unlock performance analytics."
        />
      </Box>
    );
  }

  const pnl = selectedCalendar?.total_pnl ?? 0;
  const isPositive = pnl >= 0;
  const totalTrades = selectedCalendar?.total_trades ?? 0;

  return (
    <Box>
      {/* Page metrics strip — calendar selection itself lives in AppHeader. */}
      <Box
        sx={{
          px: { xs: 2, sm: 3 },
          py: 1.25,
          bgcolor: 'background.paper',
          borderBottom: (theme) => `1px solid ${theme.palette.divider}`,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'flex-end',
          minHeight: 40,
        }}
      >
        <Stack direction="row" spacing={2} alignItems="center">
          <Box sx={{ textAlign: 'right' }}>
            <Typography
              sx={{
                fontSize: '0.6875rem',
                fontWeight: 600,
                letterSpacing: '0.05em',
                textTransform: 'uppercase',
                color: 'text.secondary',
                lineHeight: 1.1,
              }}
            >
              Trades
            </Typography>
            <Typography
              sx={{
                fontSize: '0.9375rem',
                fontWeight: 700,
                fontFeatureSettings: "'tnum' on, 'lnum' on",
                color: 'text.primary',
                mt: 0.25,
                lineHeight: 1.1,
              }}
            >
              {totalTrades.toLocaleString()}
            </Typography>
          </Box>

          <Box sx={{ textAlign: 'right' }}>
            <Typography
              sx={{
                fontSize: '0.6875rem',
                fontWeight: 600,
                letterSpacing: '0.05em',
                textTransform: 'uppercase',
                color: 'text.secondary',
                lineHeight: 1.1,
              }}
            >
              Total P&amp;L
            </Typography>
            <Stack
              direction="row"
              spacing={0.5}
              alignItems="center"
              justifyContent="flex-end"
              sx={{ mt: 0.25 }}
            >
              {isPositive ? (
                <TrendingUpIcon
                  sx={{ fontSize: 14, color: 'success.main' }}
                />
              ) : (
                <TrendingDownIcon
                  sx={{ fontSize: 14, color: 'error.main' }}
                />
              )}
              <Typography
                sx={{
                  fontSize: '0.9375rem',
                  fontWeight: 700,
                  fontFeatureSettings: "'tnum' on, 'lnum' on",
                  color: isPositive ? 'success.main' : 'error.main',
                  lineHeight: 1.1,
                }}
              >
                {isPositive ? '+' : '-'}$
                {Math.abs(pnl).toLocaleString(undefined, {
                  minimumFractionDigits: 2,
                  maximumFractionDigits: 2,
                })}
              </Typography>
            </Stack>
          </Box>
        </Stack>
      </Box>

      {/* Body */}
      <Box
        sx={{
          position: 'relative',
          px: { xs: 2, sm: 3, md: 4 },
          py: { xs: 2, sm: 3 },
          maxWidth: 1600,
          mx: 'auto',
        }}
      >
        {isSwitching || !selectedCalendar ? (
          <Box
            sx={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'center',
              py: 12,
              gap: 2,
            }}
          >
            <CircularProgress size={28} />
            <Typography
              sx={{
                fontSize: '0.8125rem',
                color: 'text.secondary',
                letterSpacing: '0.02em',
              }}
            >
              Switching calendar
            </Typography>
          </Box>
        ) : (
          <PerformanceCharts
            key={selectedCalendar.id}
            calendarId={selectedCalendar.id}
            calendar={selectedCalendar}
            accountBalance={selectedCalendar.account_balance}
            maxDailyDrawdown={selectedCalendar.max_daily_drawdown}
            monthlyTarget={selectedCalendar.monthly_target}
            scoreSettings={selectedCalendar.score_settings}
            dynamicRiskSettings={{
              account_balance: selectedCalendar.account_balance,
              risk_per_trade: selectedCalendar.risk_per_trade,
              dynamic_risk_enabled: selectedCalendar.dynamic_risk_enabled,
              increased_risk_percentage: selectedCalendar.increased_risk_percentage,
              profit_threshold_percentage: selectedCalendar.profit_threshold_percentage,
            }}
            onUpdateCalendarProperty={onUpdateCalendarProperty}
            isReadOnly
          />
        )}
      </Box>

      <OrionFab />
    </Box>
  );
};

export default PerformancePage;
